Rules.InvariantScript:
With(
   {
    truePosition: (-Self.Height) + ((App.Height * 0.5 + Self.Height / 2) * (tmrOpen_expenseForm.Value / tmrOpen_expenseForm.Duration)),
    falsePosition: ((-Self.Height - App.Height * 0.5) * (tmrClose_expenseForm.Value / tmrClose_expenseForm.Duration))

   },
   If(
       cmpModal_expenseForm.ModalActived,
       truePosition,
       falsePosition
   )
)
